operation.add:

// Initialize template loader with modification paths
$loader = new \Twig_Loader_Filesystem();

// Add modification paths with security checks
$modPaths = [
    'admin' => DIR_MODIFICATION . 'admin/view/template/',
    'catalog' => DIR_MODIFICATION . 'catalog/view/theme/'
];

foreach ($modPaths as $type => $path) {
    if (is_dir($path) && strpos($path, '..') === false) {
        $loader->addPath($path, $type);
    }
}

// Add default template path
$loader->addPath(DIR_TEMPLATE);

// Enable cache in production with directory check
if ((!defined('DEV_MODE') || !DEV_MODE) && is_writable(DIR_CACHE)) {
    $cacheDir = DIR_CACHE . 'twig/';
    if (!is_dir($cacheDir)) {
        mkdir($cacheDir, 0755, true);
    }
    $loader->setCache($cacheDir);
}


// Security: Validate controller path with additional checks
if (strpos($route, '..') !== false || 
    !is_file($file) || 
    !is_readable($file) || 
    strpos(realpath($file), DIR_APPLICATION) !== 0) {
    throw new \Exception('Security violation: Invalid controller path');
}


// Track modification timestamps for cache invalidation
static $modTimes = [];
$modTime = filemtime($filename);

if (isset($modTimes[$filename]) && $modTimes[$filename] === $modTime) {
    return $filename;
}

$modTimes[$filename] = $modTime;
